### Add this code in function.php
You can change the language code in the WF and in these functions. In this example from "it" to "en"

```php
add_action('rest_api_init', function () {
    register_rest_route('custom/v1', '/test', [
        'methods' => 'GET',
        'callback' => function () {
            return ['ok' => true];
        }
    ]);
});

add_action('rest_api_init', function () {

    register_rest_route('custom/v1', '/link-translation', [
        'methods' => 'POST',
        'callback' => 'ew_link_translation',
        'permission_callback' => '__return_true'
    ]);

});

function ew_link_translation($request) {

    $post_it = intval($request->get_param('post_it'));
    $post_en = intval($request->get_param('post_en'));

    if (!$post_it || !$post_en) {
        return new WP_Error('missing_data', 'post_it e post_en obbligatori', ['status' => 400]);
    }

    if (!get_post($post_it) || !get_post($post_en)) {
        return new WP_Error('invalid_post', 'Uno dei post non esiste', ['status' => 404]);
    }
    if (!has_filter('wpml_element_trid')) {
        return new WP_Error('wpml_missing', 'WPML non attivo', ['status' => 500]);
    }
    $element_type = 'post_post';

    $trid = apply_filters('wpml_element_trid', null, $post_it, $element_type);

    if (!$trid) {
        do_action('wpml_set_element_language_details', [
            'element_id' => $post_it,
            'element_type' => $element_type,
            'trid' => false,
            'language_code' => 'it',
            'source_language_code' => null
        ]);

        $trid = apply_filters('wpml_element_trid', null, $post_it, $element_type);
    }

    do_action('wpml_set_element_language_details', [
        'element_id' => $post_it,
        'element_type' => $element_type,
        'trid' => $trid,
        'language_code' => 'it',
        'source_language_code' => null
    ]);

    do_action('wpml_set_element_language_details', [
        'element_id' => $post_en,
        'element_type' => $element_type,
        'trid' => $trid,
        'language_code' => 'en',
        'source_language_code' => 'it'
    ]);

    return [
        'success' => true,
        'trid' => $trid,
        'post_it' => $post_it,
        'post_en' => $post_en
    ];
}

